import { jsPDF } from 'jspdf';

/**
 * 证书生成服务 - 用于创建可下载的证书PDF
 */
class CertificateGenerator {
  /**
   * 根据证书数据生成PDF证书
   * @param {Object} certificate - 证书数据
   * @returns {Promise<Blob>} 返回PDF Blob
   */
  static async generateCertificatePDF(certificate) {
    return new Promise(async (resolve, reject) => {
      try {
        // 创建PDF文档 (A4横向)
        const doc = new jsPDF({
          orientation: 'landscape',
          unit: 'mm',
          format: 'a4'
        });

        // 设置文档属性
        doc.setProperties({
          title: `${certificate.name} - ${certificate.course} Certificate`,
          subject: 'Stratford International University Certificate',
          author: 'Stratford International University',
          keywords: 'certificate, education, diploma',
          creator: 'SIU Certificate System'
        });

        // 添加水印
        this.addWatermark(doc);

        // 加载证书SVG作为背景
        await this.loadSVGBackground(doc, certificate);

        // 添加证书详细信息
        this.addCertificateDetails(doc, certificate);

        // 添加QR码 (用于验证)
        this.addVerificationQR(doc, certificate);

        // 生成PDF并返回
        const pdfBlob = doc.output('blob');
        resolve(pdfBlob);
      } catch (error) {
        console.error('PDF生成错误:', error);
        reject(error);
      }
    });
  }

  /**
   * 添加SIU验证水印
   * @param {jsPDF} doc - jsPDF文档实例
   */
  static addWatermark(doc) {
    const watermarkText = 'SIU Verified';
    
    // 保存当前图形状态
    doc.saveGraphicsState();
    
    // 设置文本属性
    doc.setTextColor(0, 48, 135); // #003087
    doc.setGState(new doc.GState({ opacity: 0.1 }));
    doc.setFontSize(60);

    // 计算页面中心
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    
    // 绘制旋转的水印
    doc.translate(pageWidth / 2, pageHeight / 2);
    doc.rotate(-45);
    doc.text(watermarkText, 0, 0, { align: 'center' });
    
    // 恢复图形状态
    doc.restoreGraphicsState();
  }

  /**
   * 加载SVG证书模板作为背景
   * @param {jsPDF} doc - jsPDF文档实例
   * @param {Object} certificate - 证书数据
   */
  static async loadSVGBackground(doc, certificate) {
    return new Promise((resolve, reject) => {
      try {
        // 创建图像对象
        const img = new Image();
        
        // 获取SVG内容并替换占位符
        fetch(certificate.processedImage || certificate.image)
          .then(response => response.text())
          .then(svgText => {
            // 替换SVG中的占位符
            svgText = svgText.replace(/\[RECIPIENT NAME\]/g, certificate.name);
            svgText = svgText.replace(/\[DATE\]/g, certificate.date);
            svgText = svgText.replace(/\[CERTIFICATE-ID\]/g, certificate.certificateId);
            svgText = svgText.replace(/\[PROGRAM\/DEGREE\]/g, certificate.english_course || certificate.course);
            svgText = svgText.replace(/\[PROGRAM_DESCRIPTION\]/g, certificate.english_description || '');
            
            // 随机生成一个哈希作为区块链验证码
            const hash = 'SIU-' + Math.random().toString(36).substring(2, 10).toUpperCase();
            svgText = svgText.replace(/\[HASH\]/g, hash);
            
            // 创建SVG数据URL
            const svgBlob = new Blob([svgText], { type: 'image/svg+xml' });
            const url = URL.createObjectURL(svgBlob);
            
            // 设置图像源
            img.onload = function() {
              // 添加图像作为背景
              doc.addImage(img, 'SVG', 0, 0, 297, 210);
              
              // 释放URL对象
              URL.revokeObjectURL(url);
              
              resolve();
            };
            
            img.onerror = function(error) {
              URL.revokeObjectURL(url);
              reject(error);
            };
            
            img.src = url;
          })
          .catch(reject);
      } catch (error) {
        reject(error);
      }
    });
  }

  /**
   * 添加证书详细信息
   * @param {jsPDF} doc - jsPDF文档实例
   * @param {Object} certificate - 证书数据
   */
  static addCertificateDetails(doc, certificate) {
    // 在合适的位置添加额外的证书信息
    // 注意：大部分信息已经包含在SVG模板中
  }

  /**
   * 添加验证QR码
   * @param {jsPDF} doc - jsPDF文档实例
   * @param {Object} certificate - 证书数据
   */
  static addVerificationQR(doc, certificate) {
    // 在未来实现：添加指向验证页面的QR码
    // 目前QR码功能暂未实现
  }

  /**
   * 下载证书PDF
   * @param {Object} certificate - 证书数据
   */
  static async downloadCertificate(certificate) {
    try {
      const pdfBlob = await this.generateCertificatePDF(certificate);
      
      // 创建下载链接
      const url = URL.createObjectURL(pdfBlob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `certificate-${certificate.certificateId}.pdf`;
      
      // 触发下载
      document.body.appendChild(link);
      link.click();
      
      // 释放URL对象
      setTimeout(() => {
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
      }, 100);
      
      return true;
    } catch (error) {
      console.error('证书下载失败:', error);
      return false;
    }
  }
}

export default CertificateGenerator;
